#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00265Custom {
public:
    __aicore__ inline KernelCa6k00265Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR tensor1, GM_ADDR tensor2, GM_ADDR bias, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        t1Gm_.SetGlobalBuffer((__gm__ float*)tensor1, totalLen_);
        t2Gm_.SetGlobalBuffer((__gm__ float*)tensor2, totalLen_);
        biasGm_.SetGlobalBuffer((__gm__ float*)bias, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueT1_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueT2_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueBias_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        uint32_t curLen = totalLen_ - base;
        if (curLen > tileLen_) curLen = tileLen_;
        CopyIn(base, curLen);

        while (true) {
            const uint32_t nextBase = base + strideElems;
            uint32_t nextLen = 0;
            if (nextBase < totalLen_) {
                nextLen = totalLen_ - nextBase;
                if (nextLen > tileLen_) nextLen = tileLen_;
                CopyIn(nextBase, nextLen);
            }

            Compute(curLen);
            CopyOut(base, curLen);

            if (nextLen == 0) break;
            base = nextBase;
            curLen = nextLen;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::LocalTensor<float> t1Local = inQueueT1_.AllocTensor<float>();
        AscendC::LocalTensor<float> t2Local = inQueueT2_.AllocTensor<float>();
        AscendC::LocalTensor<float> biasLocal = inQueueBias_.AllocTensor<float>();

        AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
        AscendC::DataCopy(t1Local, t1Gm_[gmOffset], len);
        AscendC::DataCopy(t2Local, t2Gm_[gmOffset], len);
        AscendC::DataCopy(biasLocal, biasGm_[gmOffset], len);

        inQueueX_.EnQue(xLocal);
        inQueueT1_.EnQue(t1Local);
        inQueueT2_.EnQue(t2Local);
        inQueueBias_.EnQue(biasLocal);
    }

    __aicore__ inline void Compute(uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> t1Local = inQueueT1_.DeQue<float>();
        AscendC::LocalTensor<float> t2Local = inQueueT2_.DeQue<float>();
        AscendC::LocalTensor<float> biasLocal = inQueueBias_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();

        // tmp = t1 / t2
        AscendC::Div(tmpLocal, t1Local, t2Local, len);
        // tmp = tmp + x
        AscendC::Add(tmpLocal, tmpLocal, xLocal, len);
        // y = tmp + bias
        AscendC::Add(yLocal, tmpLocal, biasLocal, len);

        tmpQueue_.FreeTensor(tmpLocal);
        outQueueY_.EnQue<float>(yLocal);

        inQueueX_.FreeTensor(xLocal);
        inQueueT1_.FreeTensor(t1Local);
        inQueueT2_.FreeTensor(t2Local);
        inQueueBias_.FreeTensor(biasLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueT1_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueT2_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueBias_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> t1Gm_;
    AscendC::GlobalTensor<float> t2Gm_;
    AscendC::GlobalTensor<float> biasGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void ca6k_00265_custom(GM_ADDR x, GM_ADDR tensor1, GM_ADDR tensor2, GM_ADDR bias, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00265Custom op;
    op.Init(x, tensor1, tensor2, bias, y, tiling_data.totalLength, tiling_data.tileLength);
    op.Process();
}
